export function notIn(text: string) {
	if (text.length === 0) throw new Error(`_not_in: text must be non-empty`);
	return {
		$type: "_not_in" as const,
		$source: "factory" as const,
		$named: true as const,
		$text: text,
		render: () => text,
		toEdit: (s: number | ByteRange, e?: number) =>
			typeof s === "number"
				? { startPos: s, endPos: e!, insertedText: text }
				: { startPos: s.start.index, endPos: s.end.index, insertedText: text },
		replace: (t: T.NotInTree) => {
			const r = t.range();
			return { startPos: r.start.index, endPos: r.end.index, insertedText: text };
		},
	};
}

